queries.sphinxql:
create table facet_local_a ( title text, brand_id integer, color_id integer, color_name string, size_id integer, size_name string, sku string );
insert into facet_local_a ( id, title, brand_id, color_id, color_name, size_id, size_name, sku ) values
(1,'p1',7,1,'red',10,'small','sku1'),
(3,'p3',7,2,'blue',10,'small','sku3'),
(5,'p5',8,1,'red',10,'small','sku5');

create table facet_local_b ( title text, brand_id integer, color_id integer, color_name string, size_id integer, size_name string, sku string );
insert into facet_local_b ( id, title, brand_id, color_id, color_name, size_id, size_name, sku ) values
(2,'p2',7,1,'red',20,'large','sku2'),
(4,'p4',7,3,'green',30,'xlarge','sku4'),
(6,'p6',8,4,'black',20,'large','sku6'),
(7,'p7',9,5,'white',10,'small','sku7');

create table facet_dist_local type='distributed' local='facet_local_a' local='facet_local_b';

create table facet_agent_a ( title text, brand_id integer, color_id integer, color_name string, size_id integer, size_name string, sku string );
insert into facet_agent_a ( id, title, brand_id, color_id, color_name, size_id, size_name, sku ) values
(1,'p1',7,1,'red',10,'small','sku1'),
(3,'p3',7,2,'blue',10,'small','sku3'),
(5,'p5',8,1,'red',10,'small','sku5');

create table facet_agent_b ( title text, brand_id integer, color_id integer, color_name string, size_id integer, size_name string, sku string );
insert into facet_agent_b ( id, title, brand_id, color_id, color_name, size_id, size_name, sku ) values
