(4,'p4',7,3,'green',30,'xlarge','sku4'),
(6,'p6',8,4,'black',20,'large','sku6'),
(7,'p7',9,5,'white',10,'small','sku7');

SELECT count(*) FROM facet_dist_local WHERE brand_id=7 AND color_id=1 LIMIT 0 FACET color_id ORDER BY FACET() ASC FACET size_id ORDER BY FACET() ASC;;


SELECT count(*) FROM facet_dist_local WHERE brand_id=7 AND color_id=1 AND size_id=10 LIMIT 0 OPTION facet_filter_mode='auto' FACET color_id ORDER BY FACET() ASC FACET size_id ORDER BY FACET() ASC;;


SELECT count(*) FROM facet_dist_local WHERE brand_id=7 AND color_id=1 LIMIT 0 OPTION facet_filter_mode='max' FACET color_id ORDER BY FACET() ASC FACET size_id ORDER BY FACET() ASC;;


SELECT count(*) FROM facet_dist_local WHERE brand_id=7 AND color_id=99 LIMIT 0 OPTION facet_filter_mode='max' FACET color_id ORDER BY FACET() ASC;;


SELECT count(*) FROM facet_dist_local WHERE brand_id=7 AND color_id=1 LIMIT 0 OPTION facet_filter_mode='max' FACET color_id ORDER BY FACET() ASC; SELECT count(*) FROM facet_dist_local WHERE brand_id=7;;


SELECT count(*) FROM facet_dist_agent WHERE brand_id=7 AND color_id=1 LIMIT 0 FACET color_id ORDER BY FACET() ASC FACET size_id ORDER BY FACET() ASC;;


SELECT count(*) FROM facet_dist_agent WHERE brand_id=7 AND color_id=1 AND size_id=10 LIMIT 0 OPTION facet_filter_mode='auto' FACET color_id ORDER BY FACET() ASC FACET size_id ORDER BY FACET() ASC;;


SELECT count(*) FROM facet_dist_agent WHERE brand_id=7 AND color_id=1 LIMIT 0 OPTION facet_filter_mode='max' FACET color_id ORDER BY FACET() ASC FACET size_id ORDER BY FACET() ASC;;


SELECT count(*) FROM facet_dist_agent WHERE brand_id=7 AND color_id=99 LIMIT 0 OPTION facet_filter_mode='max' FACET color_id ORDER BY FACET() ASC;;


SELECT count(*) FROM facet_dist_agent WHERE brand_id=7 AND color_id=1 LIMIT 0 OPTION facet_filter_mode='max' FACET color_id ORDER BY FACET() ASC; SELECT count(*) FROM facet_dist_agent WHERE brand_id=7;;

